import type { UseMutationResult, UseQueryResult } from '@tanstack/react-query';
import type {
  KangurAiTutorChatResponse,
  KangurAiTutorConversationContext,
  KangurAiTutorUsageSummary,
} from '../../../../src/shared/contracts/kangur-ai-tutor';
import type { KangurAiTutorContent } from '../../../../src/shared/contracts/kangur-ai-tutor-content';
import type { KangurAiTutorNativeGuideStore } from '../../../../src/shared/contracts/kangur-ai-tutor-native-guide';
import {
  useKangurMobileMutationV2,
  useKangurMobileQueryV2,
} from '../query/kangurMobileQueryFactories';

export type KangurMobileAiTutorQuickAction = {
  id: string;
  label: string;
  prompt: string;
};

export type TutorUsageQueryResult = {
  message: string | null;
  usage: KangurAiTutorUsageSummary | null;
};

export type KangurMobileAiTutorQueries = {
  contentQuery: UseQueryResult<KangurAiTutorContent, Error>;
  nativeGuideQuery: UseQueryResult<KangurAiTutorNativeGuideStore, Error>;
  usageQuery: UseQueryResult<TutorUsageQueryResult, Error>;
};

export const createTutorFetchErrorMessage = (
  locale: 'de' | 'en' | 'pl',
): string =>
  ({
    de: 'Der KI-Tutor konnte nicht geöffnet werden.',
    en: 'Could not open AI Tutor.',
    pl: 'Nie udało się otworzyć AI Tutora.',
  })[locale];

export const readResponseMessage = async (response: Response): Promise<string | null> => {
  try {
    const payload = (await response.json()) as Record<string, unknown>;
    const message = payload['message'];
    return typeof message === 'string' && message.trim().length > 0
      ? message.trim()
      : null;
  } catch {
    return null;
  }
};

const fetchTutorContent = async (apiBaseUrl: string, locale: 'de' | 'en' | 'pl'): Promise<KangurAiTutorContent> => {
  const response = await fetch(
    `${apiBaseUrl}/api/kangur/ai-tutor/content?locale=${encodeURIComponent(locale)}`,
    {
      cache: 'no-store',
      credentials: 'include',
    },
  );
  if (!response.ok) {
    throw new Error(createTutorFetchErrorMessage(locale));
  }
  return (await response.json()) as KangurAiTutorContent;
};

const fetchTutorNativeGuide = async (apiBaseUrl: string, locale: 'de' | 'en' | 'pl'): Promise<KangurAiTutorNativeGuideStore> => {
  const response = await fetch(
    `${apiBaseUrl}/api/kangur/ai-tutor/native-guide?locale=${encodeURIComponent(locale)}`,
    {
      cache: 'no-store',
      credentials: 'include',
    },
  );
  if (!response.ok) {
    throw new Error(createTutorFetchErrorMessage(locale));
  }
  return (await response.json()) as KangurAiTutorNativeGuideStore;
};

const fetchTutorUsage = async (apiBaseUrl: string, locale: 'de' | 'en' | 'pl'): Promise<TutorUsageQueryResult> => {
  const response = await fetch(`${apiBaseUrl}/api/kangur/ai-tutor/usage`, {
    cache: 'no-store',
    credentials: 'include',
  });

  if (!response.ok) {
    const message = (await readResponseMessage(response)) ?? createTutorFetchErrorMessage(locale);
    return { message, usage: null };
  }

  const payload = (await response.json()) as { usage?: KangurAiTutorUsageSummary };
  return { message: null, usage: payload.usage ?? null };
};

export const useKangurMobileAiTutorQueries = ({
  apiBaseUrl,
  canLoadTutorCatalog,
  enabled,
  isAuthenticated,
  isRestoringAuth,
  locale,
  userId,
}: {
  apiBaseUrl: string;
  canLoadTutorCatalog: boolean;
  enabled: boolean;
  isAuthenticated: boolean;
  isRestoringAuth: boolean;
  locale: 'de' | 'en' | 'pl';
  userId: string;
}): KangurMobileAiTutorQueries => {
  const contentQueryKey = ['kangur-mobile', 'ai-tutor', 'content', apiBaseUrl, locale] as const;
  const nativeGuideQueryKey = [
    'kangur-mobile',
    'ai-tutor',
    'native-guide',
    apiBaseUrl,
    locale,
  ] as const;
  const usageQueryKey = ['kangur-mobile', 'ai-tutor', 'usage', apiBaseUrl, userId] as const;

  const contentQuery = useKangurMobileQueryV2<KangurAiTutorContent>({
    enabled: canLoadTutorCatalog,
    queryKey: contentQueryKey,
    queryFn: () => fetchTutorContent(apiBaseUrl, locale),
    staleTime: 300_000,
    meta: {
      source: 'kangur.mobile.ai-tutor.content',
      operation: 'detail',
      resource: 'kangur.mobile.ai-tutor.content',
      queryKey: contentQueryKey,
      description: 'Loads Kangur mobile AI tutor content.',
      tags: ['kangur-mobile', 'ai-tutor', 'content'],
    },
  });

  const nativeGuideQuery = useKangurMobileQueryV2<KangurAiTutorNativeGuideStore>({
    enabled: canLoadTutorCatalog,
    queryKey: nativeGuideQueryKey,
    queryFn: () => fetchTutorNativeGuide(apiBaseUrl, locale),
    staleTime: 300_000,
    meta: {
      source: 'kangur.mobile.ai-tutor.native-guide',
      operation: 'detail',
      resource: 'kangur.mobile.ai-tutor.native-guide',
      queryKey: nativeGuideQueryKey,
      description: 'Loads Kangur mobile AI tutor native guide.',
      tags: ['kangur-mobile', 'ai-tutor', 'native-guide'],
    },
  });

  const usageQuery = useKangurMobileQueryV2<TutorUsageQueryResult>({
    enabled: enabled && isAuthenticated && !isRestoringAuth,
    queryKey: usageQueryKey,
    queryFn: () => fetchTutorUsage(apiBaseUrl, locale),
    staleTime: 30_000,
    meta: {
      source: 'kangur.mobile.ai-tutor.usage',
      operation: 'detail',
      resource: 'kangur.mobile.ai-tutor.usage',
      queryKey: usageQueryKey,
      description: 'Loads Kangur mobile AI tutor usage summary.',
      tags: ['kangur-mobile', 'ai-tutor', 'usage'],
    },
  });

  return { contentQuery, nativeGuideQuery, usageQuery };
};

export const useKangurMobileAiTutorMutation = ({
  apiBaseUrl,
  context,
  locale,
}: {
  apiBaseUrl: string;
  context: KangurAiTutorConversationContext;
  locale: 'de' | 'en' | 'pl';
}): UseMutationResult<KangurAiTutorChatResponse, Error, KangurMobileAiTutorQuickAction> => {
  const mutationKey = ['kangur-mobile', 'ai-tutor', 'chat', apiBaseUrl, locale] as const;
  return useKangurMobileMutationV2<KangurAiTutorChatResponse, KangurMobileAiTutorQuickAction>({
    mutationKey,
    mutationFn: async (
      action: KangurMobileAiTutorQuickAction,
    ): Promise<KangurAiTutorChatResponse> => {
      const response = await fetch(`${apiBaseUrl}/api/kangur/ai-tutor/chat`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        credentials: 'include',
        body: JSON.stringify({
          messages: [
            {
              role: 'user',
              content: action.prompt,
            },
          ],
          context,
        }),
      });

      if (!response.ok) {
        const message = (await readResponseMessage(response)) ?? createTutorFetchErrorMessage(locale);
        throw new Error(message);
      }

      const data = (await response.json()) as unknown;
      return data as KangurAiTutorChatResponse;
    },
    meta: {
      source: 'kangur.mobile.ai-tutor.chat',
      operation: 'action',
      resource: 'kangur.mobile.ai-tutor.chat',
      mutationKey,
      description: 'Sends Kangur mobile AI tutor chat prompts.',
      tags: ['kangur-mobile', 'ai-tutor', 'chat'],
    },
  });
};

import { useState, useEffect } from 'react';
import { useQueryClient, type QueryClient, type UseQueryResult } from '@tanstack/react-query';
import type {
  KangurDuelChoice,
  KangurDuelPlayer,
  KangurDuelQuestion,
  KangurDuelReactionType,
  KangurDuelSession,
  KangurDuelStateResponse,
  KangurDuelSpectatorStateResponse,
  KangurDuelReaction,
} from '@kangur/contracts/kangur-duels';

import { useKangurMobileAuth } from '../auth/KangurMobileAuthContext';
import { useKangurMobileI18n } from '../i18n/kangurMobileI18n';
import { useKangurMobileRuntime } from '../providers/KangurRuntimeContext';
import { createMobileDuelSpectatorId, resolveCurrentQuestion } from './useKangurMobileDuelSession.helpers';
import { toSessionErrorMessage } from './useKangurMobileDuelSession.errors';
import { type DuelApiClient } from './useKangurMobileDuelsLobbyQueries';
import { safeSetInterval, safeClearInterval } from '@/shared/lib/timers';
import { useKangurMobileQueryV2 } from '../query/kangurMobileQueryFactories';

const MOBILE_DUEL_SESSION_POLL_MS = 4_000;
const MOBILE_DUEL_HEARTBEAT_MS = 15_000;

export interface UseKangurMobileDuelSessionResult {
  actionError: string | null;
  currentQuestion: KangurDuelQuestion | null;
  error: string | null;
  isAuthenticated: boolean;
  isLoading: boolean;
  isMutating: boolean;
  isRestoringAuth: boolean;
  isSpectating: boolean;
  leaveSession: () => Promise<boolean>;
  player: KangurDuelPlayer | null;
  refresh: () => Promise<void>;
  sendReaction: (type: KangurDuelReactionType) => Promise<void>;
  session: KangurDuelSession | null;
  spectatorCount: number;
  submitAnswer: (choice: KangurDuelChoice) => Promise<void>;
}

interface DuelActions {
  leaveSession: () => Promise<boolean>;
  sendReaction: (type: KangurDuelReactionType) => Promise<void>;
  submitAnswer: (choice: KangurDuelChoice) => Promise<void>;
}

interface DuelActionsDeps {
  apiClient: DuelApiClient;
  copy: (v: Record<string, string>) => string;
  queryClient: QueryClient;
  playerKey: readonly unknown[];
  spectatorKey: readonly unknown[];
  isSpectating: boolean;
  normalizedSessionId: string;
  currentQuestion: KangurDuelQuestion | null;
  setIsMutating: (val: boolean) => void;
  setActionError: (val: string | null) => void;
}

function useDuelActions(deps: DuelActionsDeps): DuelActions {
  const { apiClient, copy, queryClient, playerKey, spectatorKey, isSpectating, normalizedSessionId, currentQuestion, setIsMutating, setActionError } = deps;

  const execute = async <T,>(action: () => Promise<T>, fallback: string): Promise<T | null> => {
    setIsMutating(true); setActionError(null);
    try { return await action(); } catch (err) { setActionError(toSessionErrorMessage(err, fallback, copy)); return null; }
    finally { setIsMutating(false); }
  };

  const leaveSession = async (): Promise<boolean> => {
    if (isSpectating) return false;
    const resp = await execute(() => apiClient.leaveDuel({ reason: 'mobile_exit', sessionId: normalizedSessionId }, { cache: 'no-store' }), copy({ de: 'Fehler', en: 'Error', pl: 'Błąd' }));
    if (resp === null) return false;
    queryClient.setQueryData<KangurDuelStateResponse>(playerKey, resp);
    return true;
  };

  const sendReaction = async (type: KangurDuelReactionType): Promise<void> => {
    const resp = await execute<{ reaction: KangurDuelReaction }>(() => apiClient.reactToDuel({ sessionId: normalizedSessionId, type }, { cache: 'no-store' }), copy({ de: 'Fehler', en: 'Error', pl: 'Błąd' }));
    if (resp === null) return;
    const activeKey = isSpectating ? spectatorKey : playerKey;
    queryClient.setQueryData<KangurDuelStateResponse | KangurDuelSpectatorStateResponse>(activeKey, (cur) => {
      if (!cur || typeof cur !== 'object' || !('session' in cur)) return cur;
      const state = cur as { session: KangurDuelSession };
      return {
        ...cur,
        session: {
          ...state.session,
          recentReactions: [...(state.session.recentReactions ?? []), resp.reaction].slice(-8),
        },
      };
    });
  };

  const submitAnswer = async (choice: KangurDuelChoice): Promise<void> => {
    if (isSpectating || currentQuestion === null) return;
    const resp = await execute(() => apiClient.answerDuel({ choice, clientTimestamp: new Date().toISOString(), questionId: currentQuestion.id, sessionId: normalizedSessionId }, { cache: 'no-store' }), copy({ de: 'Fehler', en: 'Error', pl: 'Błąd' }));
    if (resp !== null) queryClient.setQueryData<KangurDuelStateResponse>(playerKey, resp);
  };

  return { leaveSession, sendReaction, submitAnswer };
}

function getLearnerId(user: { activeLearner?: { id: string }; email?: string; id?: string } | null): string {
  return user?.activeLearner?.id ?? user?.email ?? user?.id ?? 'guest';
}

function useDuelQueries({
  apiClient,
  hasSessionId,
  isAuthenticated,
  isSpectating,
  normalizedSessionId,
  playerKey,
  spectatorKey,
  spectatorId,
}: {
  apiClient: DuelApiClient;
  hasSessionId: boolean;
  isAuthenticated: boolean;
  isSpectating: boolean;
  normalizedSessionId: string;
  playerKey: readonly unknown[];
  spectatorKey: readonly unknown[];
  spectatorId: string;
}): {
  playerQuery: UseQueryResult<KangurDuelStateResponse, Error>;
  spectatorQuery: UseQueryResult<KangurDuelSpectatorStateResponse, Error>;
} {
  const playerQuery = useKangurMobileQueryV2<KangurDuelStateResponse>({
    enabled: hasSessionId && isAuthenticated && !isSpectating,
    queryKey: playerKey,
    queryFn: async (): Promise<KangurDuelStateResponse> =>
      apiClient.getDuelState(normalizedSessionId, { cache: 'no-store' }),
    refetchInterval: MOBILE_DUEL_SESSION_POLL_MS,
    staleTime: 2_000,
    meta: {
      source: 'kangur.mobile.duels.session.player',
      operation: 'detail',
      resource: 'kangur.mobile.duels.session.player',
      queryKey: playerKey,
      description: 'Loads Kangur mobile duel player session state.',
      tags: ['kangur-mobile', 'duels', 'session'],
    },
  });

  const spectatorQuery = useKangurMobileQueryV2<KangurDuelSpectatorStateResponse>({
    enabled: hasSessionId && isSpectating,
    queryKey: spectatorKey,
    queryFn: async (): Promise<KangurDuelSpectatorStateResponse> =>
      apiClient.getDuelSpectatorState(normalizedSessionId, { spectatorId }, { cache: 'no-store' }),
    refetchInterval: MOBILE_DUEL_SESSION_POLL_MS,
    staleTime: 2_000,
    meta: {
      source: 'kangur.mobile.duels.session.spectator',
      operation: 'detail',
      resource: 'kangur.mobile.duels.session.spectator',
      queryKey: spectatorKey,
      description: 'Loads Kangur mobile duel spectator session state.',
      tags: ['kangur-mobile', 'duels', 'session'],
    },
  });

  return { playerQuery, spectatorQuery };
}

function useDuelHeartbeat({
  apiClient,
  duelSession,
  hasSessionId,
  isAuthenticated,
  isSpectating,
  normalizedSessionId,
  playerKey,
  queryClient,
}: {
  apiClient: DuelApiClient;
  duelSession: KangurDuelSession | null;
  hasSessionId: boolean;
  isAuthenticated: boolean;
  isSpectating: boolean;
  normalizedSessionId: string;
  playerKey: readonly unknown[];
  queryClient: QueryClient;
}): void {
  useEffect(() => {
    const isInactive =
      !hasSessionId ||
      !isAuthenticated ||
      duelSession === null ||
      duelSession.status === 'completed' ||
      duelSession.status === 'aborted';
    if (isSpectating || isInactive) return undefined;

    const intervalId = safeSetInterval(() => {
      void apiClient
        .heartbeatDuel(
          { clientTimestamp: new Date().toISOString(), sessionId: normalizedSessionId },
          { cache: 'no-store' },
        )
        .then((resp) => {
          queryClient.setQueryData(playerKey, resp);
        })
        .catch(() => {});
    }, MOBILE_DUEL_HEARTBEAT_MS);
    return () => {
      safeClearInterval(intervalId);
    };
  }, [
    apiClient,
    duelSession,
    hasSessionId,
    isAuthenticated,
    isSpectating,
    normalizedSessionId,
    playerKey,
    queryClient,
  ]);
}

type DuelStateResolution = {
  duelSession: KangurDuelSession | null;
  player: KangurDuelPlayer | null;
  isRestoringAuth: boolean;
  isLoading: boolean;
  spectatorCount: number;
};

function resolveSpectatorState(
  spectatorQuery: UseQueryResult<KangurDuelSpectatorStateResponse, Error>,
  isRestoringAuth: boolean,
): DuelStateResolution {
  const duelSession = spectatorQuery.data?.session ?? null;
  return {
    duelSession,
    player: null,
    isRestoringAuth,
    isLoading: spectatorQuery.isLoading,
    spectatorCount: duelSession?.spectatorCount ?? 0,
  };
}

function resolvePlayerState(
  playerQuery: UseQueryResult<KangurDuelStateResponse, Error>,
  isRestoringAuth: boolean,
): DuelStateResolution {
  const duelSession = playerQuery.data?.session ?? null;
  return {
    duelSession,
    player: playerQuery.data?.player ?? null,
    isRestoringAuth,
    isLoading: isRestoringAuth || playerQuery.isLoading,
    spectatorCount: duelSession?.spectatorCount ?? 0,
  };
}

function useDuelStateResolution({
  isSpectating,
  playerQuery,
  spectatorQuery,
  isLoadingAuth,
  isAuthenticated,
}: {
  isSpectating: boolean;
  playerQuery: UseQueryResult<KangurDuelStateResponse, Error>;
  spectatorQuery: UseQueryResult<KangurDuelSpectatorStateResponse, Error>;
  isLoadingAuth: boolean;
  isAuthenticated: boolean;
}): DuelStateResolution {
  const isRestoringAuth = isLoadingAuth && !isAuthenticated;

  if (isSpectating) {
    return resolveSpectatorState(spectatorQuery, isRestoringAuth);
  }

  return resolvePlayerState(playerQuery, isRestoringAuth);
}

export const useKangurMobileDuelSession = (
  sessionId: string | null,
  options: { spectate?: boolean } = {},
): UseKangurMobileDuelSessionResult => {
  const { copy } = useKangurMobileI18n();
  const queryClient = useQueryClient();
  const { apiBaseUrl, apiClient: rawApiClient } = useKangurMobileRuntime();
  const apiClient = rawApiClient as DuelApiClient;
  const { isLoadingAuth, session: authSession } = useKangurMobileAuth();

  const [actionError, setActionError] = useState<string | null>(null);
  const [isMutating, setIsMutating] = useState(false);
  const [spectatorId] = useState(createMobileDuelSpectatorId);

  const learnerId = getLearnerId(authSession.user);
  const isAuthenticated = authSession.status === 'authenticated';
  const isSpectating = options.spectate === true;
  const normalizedSessionId = sessionId?.trim() ?? '';
  const hasSessionId = normalizedSessionId.length > 0;

  const playerKey = ['kangur-mobile', 'duels', 'session', apiBaseUrl, learnerId, normalizedSessionId] as const;
  const spectatorKey = ['kangur-mobile', 'duels', 'spectator-session', apiBaseUrl, normalizedSessionId, spectatorId] as const;

  const { playerQuery, spectatorQuery } = useDuelQueries({
    apiClient, hasSessionId, isAuthenticated, isSpectating, normalizedSessionId, playerKey, spectatorKey, spectatorId
  });

  const { duelSession, player, isRestoringAuth, isLoading, spectatorCount } = useDuelStateResolution({
    isSpectating, playerQuery, spectatorQuery, isLoadingAuth, isAuthenticated
  });

  const currentQuestion = resolveCurrentQuestion(duelSession, isSpectating, player);

  useDuelHeartbeat({
    apiClient, duelSession, hasSessionId, isAuthenticated, isSpectating, normalizedSessionId, playerKey, queryClient
  });

  const actions = useDuelActions({
    apiClient, copy, queryClient, playerKey, spectatorKey, isSpectating, normalizedSessionId, currentQuestion, setIsMutating, setActionError
  });

  const error = toSessionErrorMessage(isSpectating ? spectatorQuery.error : playerQuery.error, copy({ de: 'Fehler', en: 'Error', pl: 'Błąd' }), copy);

  return {
    actionError,
    currentQuestion,
    error,
    isAuthenticated,
    isLoading,
    isMutating,
    isRestoringAuth,
    isSpectating,
    leaveSession: actions.leaveSession,
    player,
    refresh: async (): Promise<void> => {
      if (isSpectating) await spectatorQuery.refetch(); else await playerQuery.refetch();
    },
    sendReaction: actions.sendReaction,
    session: duelSession,
    spectatorCount,
    submitAnswer: actions.submitAnswer,
  };
};

import type { KangurDuelLeaderboardEntry } from '@kangur/contracts/kangur-duels';
import { useMemo } from 'react';

import { useKangurMobileAuth } from '../auth/KangurMobileAuthContext';
import { useKangurMobileI18n } from '../i18n/kangurMobileI18n';
import { useKangurMobileRuntime } from '../providers/KangurRuntimeContext';
import { useKangurMobileQueryV2 } from '../query/kangurMobileQueryFactories';
import { toDuelsSummaryErrorMessage } from './useKangurMobileLearnerDuelsSummary.errors';
import { useSummaryIdentity } from './useDuelsSummaryIdentity';
import { useDuelsSummaryRematch } from './useDuelsSummaryRematch';
export type { UseKangurMobileLearnerDuelsSummaryResult } from './duels-summary-types';
import type { UseKangurMobileLearnerDuelsSummaryResult } from './duels-summary-types';
import type { DuelApiClient } from './useKangurMobileDuelsLobbyQueries';

function resolveLearnerRank(
  activeLearnerId: string | null, 
  entries: KangurDuelLeaderboardEntry[]
): { rank: number | null; entry: KangurDuelLeaderboardEntry | null } {
  const index = activeLearnerId !== null ? entries.findIndex((e) => e.learnerId === activeLearnerId) : -1;
  return { rank: index >= 0 ? index + 1 : null, entry: index >= 0 ? (entries[index] ?? null) : null };
}

function resolveOpponents(data: { entries: KangurDuelLeaderboardEntry[] } | undefined, opponentsLimit: number): KangurDuelLeaderboardEntry[] {
  const rawEntries = data?.entries ?? [];
  return [...rawEntries]
    .sort((l, r) => Date.parse(r.lastPlayedAt) - Date.parse(l.lastPlayedAt))
    .slice(0, opponentsLimit);
}

export const useKangurMobileLearnerDuelsSummary = ({
  leaderboardLimit,
  leaderboardLookbackDays,
  opponentsLimit,
}: {
  leaderboardLimit: number;
  leaderboardLookbackDays: number;
  opponentsLimit: number;
}): UseKangurMobileLearnerDuelsSummaryResult => {
  const { copy } = useKangurMobileI18n();
  const { apiBaseUrl, apiClient: rawApiClient } = useKangurMobileRuntime();
  const apiClient = rawApiClient as unknown as DuelApiClient;
  const { isLoadingAuth, session: authSession } = useKangurMobileAuth();

  const { learnerIdentity, activeLearnerId } = useSummaryIdentity(authSession);
  const isAuthenticated = authSession.status === 'authenticated';
  const isRestoringAuth = isLoadingAuth && !isAuthenticated;

  const queryKeyBase = useMemo(
    () => ({
      leaderboard: ['kangur-mobile', 'duels-summary', 'leaderboard', apiBaseUrl, learnerIdentity, leaderboardLimit, leaderboardLookbackDays] as const,
      opponents: ['kangur-mobile', 'duels-summary', 'opponents', apiBaseUrl, learnerIdentity, opponentsLimit] as const,
    }),
    [apiBaseUrl, learnerIdentity, leaderboardLimit, leaderboardLookbackDays, opponentsLimit],
  );

  const leaderboardQuery = useKangurMobileQueryV2({
    enabled: isAuthenticated,
    queryKey: queryKeyBase.leaderboard,
    queryFn: async () => apiClient.getDuelLeaderboard({ limit: leaderboardLimit, lookbackDays: leaderboardLookbackDays }, { cache: 'no-store' }),
    staleTime: 30_000,
    meta: {
      source: 'kangur.mobile.duels.summary.leaderboard',
      operation: 'list',
      resource: 'kangur.mobile.duels.leaderboard',
      queryKey: queryKeyBase.leaderboard,
      description: 'Loads Kangur mobile duel leaderboard summary.',
      tags: ['kangur-mobile', 'duels', 'leaderboard'],
    },
  });

  const opponentsQuery = useKangurMobileQueryV2({
    enabled: isAuthenticated,
    queryKey: queryKeyBase.opponents,
    queryFn: async () => apiClient.listDuelOpponents({ limit: opponentsLimit }, { cache: 'no-store' }),
    staleTime: 30_000,
    meta: {
      source: 'kangur.mobile.duels.summary.opponents',
      operation: 'list',
      resource: 'kangur.mobile.duels.opponents',
      queryKey: queryKeyBase.opponents,
      description: 'Loads Kangur mobile duel opponents summary.',
      tags: ['kangur-mobile', 'duels', 'opponents'],
    },
  });

  const { rank: currentRank, entry: currentEntry } = resolveLearnerRank(activeLearnerId, leaderboardQuery.data?.entries ?? []);

  const opponents = useMemo(() => resolveOpponents(opponentsQuery.data, opponentsLimit), [opponentsLimit, opponentsQuery.data]);

  const { actionError, isActionPending, pendingOpponentLearnerId, createRematch } = useDuelsSummaryRematch(apiClient, queryKeyBase);

  return {
    actionError,
    createRematch,
    currentEntry,
    currentRank,
    error: toDuelsSummaryErrorMessage(opponentsQuery.error, copy) ?? toDuelsSummaryErrorMessage(leaderboardQuery.error, copy),
    isActionPending,
    isAuthenticated,
    isLoading: isRestoringAuth || leaderboardQuery.isLoading || opponentsQuery.isLoading,
    isRestoringAuth,
    opponents,
    pendingOpponentLearnerId,
    refresh: async (): Promise<void> => {
      await Promise.all([leaderboardQuery.refetch(), opponentsQuery.refetch()]);
    },
  };
};

import { useQueryClient, type QueryClient } from '@tanstack/react-query';
import type { KangurDuelOpponentEntry } from '@kangur/contracts/kangur-duels';
import { useMemo, useState } from 'react';

import { useKangurMobileAuth } from '../auth/KangurMobileAuthContext';
import {
  MOBILE_DUEL_DEFAULT_DIFFICULTY,
  MOBILE_DUEL_DEFAULT_OPERATION,
  MOBILE_DUEL_DEFAULT_QUESTION_COUNT,
  MOBILE_DUEL_DEFAULT_TIME_PER_QUESTION_SEC,
} from '../duels/mobileDuelDefaults';
import { useKangurMobileI18n } from '../i18n/kangurMobileI18n';
import { useKangurMobileRuntime } from '../providers/KangurRuntimeContext';
import { resolveMobileDuelErrorMessage } from '../duels/mobileDuelErrorMessages';
import type { DuelApiClient } from '../duels/useKangurMobileDuelsLobbyQueries';
import { useKangurMobileQueryV2 } from '../query/kangurMobileQueryFactories';

const MOBILE_HOME_DUELS_REMATCH_LIMIT = 4;

type UseKangurMobileHomeDuelsRematchesResult = {
  actionError: string | null;
  createRematch: (opponentLearnerId: string) => Promise<string | null>;
  error: string | null;
  isActionPending: boolean;
  isAuthenticated: boolean;
  isLoading: boolean;
  isRestoringAuth: boolean;
  opponents: KangurDuelOpponentEntry[];
  refresh: () => Promise<void>;
};

type UseKangurMobileHomeDuelsRematchesOptions = {
  enabled?: boolean;
};

function resolveRematchesIdentity(session: ReturnType<typeof useKangurMobileAuth>['session']): string {
    const user = session.user;
    return user?.activeLearner?.id ?? user?.email ?? user?.id ?? 'guest';
}

async function performRematch(
  apiClient: DuelApiClient,
  queryClient: QueryClient,
  rematchesQueryKey: readonly string[],
  opponentLearnerId: string
): Promise<string | null> {
    const response = await apiClient.createDuel({
        mode: 'challenge', visibility: 'private', opponentLearnerId,
        operation: MOBILE_DUEL_DEFAULT_OPERATION, difficulty: MOBILE_DUEL_DEFAULT_DIFFICULTY,
        questionCount: MOBILE_DUEL_DEFAULT_QUESTION_COUNT, timePerQuestionSec: MOBILE_DUEL_DEFAULT_TIME_PER_QUESTION_SEC,
    }, { cache: 'no-store' });
    await queryClient.invalidateQueries({ queryKey: rematchesQueryKey });
    return response.session.id;
}

export const useKangurMobileHomeDuelsRematches = ({
  enabled = true,
}: UseKangurMobileHomeDuelsRematchesOptions = {}): UseKangurMobileHomeDuelsRematchesResult => {
  const queryClient = useQueryClient();
  const { copy } = useKangurMobileI18n();
  const { apiBaseUrl, apiClient } = useKangurMobileRuntime();
  const { isLoadingAuth, session } = useKangurMobileAuth();
  const [actionError, setActionError] = useState<string | null>(null);
  const [isActionPending, setIsActionPending] = useState(false);

  const learnerIdentity = resolveRematchesIdentity(session);
  const isAuthenticated = session.status === 'authenticated';
  const isRestoringAuth = isLoadingAuth && !isAuthenticated;
  const isQueryEnabled = enabled && isAuthenticated;
  const rematchesQueryKey = ['kangur-mobile', 'home', 'duels-rematches', apiBaseUrl, learnerIdentity] as const;

  const rematchesQuery = useKangurMobileQueryV2({
    enabled: isQueryEnabled,
    queryKey: rematchesQueryKey,
    queryFn: async () => apiClient.listDuelOpponents({ limit: MOBILE_HOME_DUELS_REMATCH_LIMIT }, { cache: 'no-store' }),
    staleTime: 30_000,
    meta: {
      source: 'kangur.mobile.home.duels.rematches',
      operation: 'list',
      resource: 'kangur.mobile.home.duels.rematches',
      queryKey: rematchesQueryKey,
      description: 'Loads Kangur mobile home duel rematch opponents.',
      tags: ['kangur-mobile', 'home', 'duels', 'rematches'],
    },
  });

  const opponents = useMemo(
    () => [...(rematchesQuery.data?.entries ?? [])]
        .sort((l, r) => Date.parse(r.lastPlayedAt) - Date.parse(l.lastPlayedAt))
        .slice(0, MOBILE_HOME_DUELS_REMATCH_LIMIT),
    [rematchesQuery.data?.entries],
  );

  const createRematch = async (opponentLearnerId: string): Promise<string | null> => {
      setActionError(null);
      setIsActionPending(true);
      try {
        return await performRematch(apiClient, queryClient, rematchesQueryKey, opponentLearnerId);
      } catch (err: unknown) {
        const fallback = { de: 'Der private Rückkampf konnte nicht erstellt werden.', en: 'Could not create the private rematch.', pl: 'Nie udało się utworzyć prywatnego rewanżu.' };
        setActionError(resolveMobileDuelErrorMessage({
            error: err, copy, fallback,
            unauthorized: { de: 'Melde dich an, um ein privates Rückspiel zu senden.', en: 'Sign in to send a private rematch.', pl: 'Zaloguj się, aby wysłać prywatny rewanż.' },
        }) ?? copy(fallback));
        return null;
      } finally {
        setIsActionPending(false);
      }
  };

  return {
    actionError,
    createRematch,
    error: resolveMobileDuelErrorMessage({
      error: rematchesQuery.error, copy,
      fallback: { de: 'Die letzten Rivalen konnten nicht geladen werden.', en: 'Could not load recent opponents.', pl: 'Nie udało się pobrać ostatnich rywali.' },
      unauthorized: { de: 'Melde dich an, um letzte Rivalen zu laden.', en: 'Sign in to load recent opponents.', pl: 'Zaloguj się, aby pobrać ostatnich rywali.' },
    }),
    isActionPending,
    isAuthenticated,
    isLoading: isRestoringAuth || (isQueryEnabled && rematchesQuery.isLoading),
    isRestoringAuth,
    opponents,
    refresh: async () => { if (isQueryEnabled) await rematchesQuery.refetch(); },
  };
};

