  type KangurMobileRuntime,
} from './KangurRuntimeContext.shared';

const KANGUR_PROGRESS_STORAGE_KEY = 'sprycio_progress';
const KANGUR_PROGRESS_OWNER_STORAGE_KEY = 'sprycio_progress_owner';

export const readWebCookieValue = (name: string): string | null => {
  if (typeof document === 'undefined' || document === null) {
    return null;
  }

  const cookiePrefix = `${name}=`;
  const rawCookie = document.cookie
    .split(';')
    .map((entry) => entry.trim())
    .find((entry) => entry.startsWith(cookiePrefix));

  return rawCookie ? decodeURIComponent(rawCookie.slice(cookiePrefix.length)) : null;
};

export const buildKangurMobileRuntimeHeaders = (
  storage: KangurClientStorageAdapter,
  webCookieToken: string | null
): Headers => {
  const headers = new Headers();
  const activeLearnerId = storage.getItem(KANGUR_MOBILE_ACTIVE_LEARNER_STORAGE_KEY);
  const bearerToken = storage.getItem(KANGUR_MOBILE_AUTH_BEARER_TOKEN_STORAGE_KEY);

  if (activeLearnerId !== null) {
    headers.set(KANGUR_ACTIVE_LEARNER_HEADER, activeLearnerId);
  }
  if (bearerToken !== null) {
    headers.set('Authorization', `Bearer ${bearerToken}`);
  }

  const csrfToken = resolveKangurMobileCsrfRequestToken({
    storage,
    webCookieToken,
  });
  if (csrfToken !== null) {
    headers.set('x-csrf-token', csrfToken);
  }

  return headers;
};

export const createTrackedKangurMobileProgressStore = (
  baseProgressStore: KangurProgressStore,
  storage: KangurClientStorageAdapter
): KangurProgressStore => ({
  ...baseProgressStore,
  saveProgress: (progress) => {
    const normalizedProgress = baseProgressStore.saveProgress(progress);

    persistKangurMobileHomeLessonCheckpoints({
      learnerIdentity: resolveKangurMobileHomeLessonCheckpointIdentity(storage),
      snapshot: buildPersistedKangurMobileHomeLessonCheckpointSnapshot({
        progress: normalizedProgress,
      }),
      storage,
    });

    return normalizedProgress;
  },
});

const createKangurMobileApiBaseUrlState = (): ReturnType<typeof resolveKangurMobileApiBaseUrl> =>
  resolveKangurMobileApiBaseUrl({
    configuredApiBaseUrl: resolveKangurMobilePublicConfig().apiUrl ?? null,
    developmentHost: extractExpoDevelopmentHost({
      hostUri: (Constants.expoConfig?.hostUri ?? Constants.platform?.hostUri ?? null),
      linkingUri: Constants.linkingUri ?? null,
    }),
    platformOs: Platform.OS,
  });

const createKangurMobileApiClient = (
  apiBaseUrl: string,
  storage: KangurClientStorageAdapter
): ReturnType<typeof createKangurApiClient> =>
  createKangurApiClient({
    baseUrl: apiBaseUrl,
    credentials: 'include',
    fetchImpl: fetch,
    getHeaders: () => buildKangurMobileRuntimeHeaders(storage, readWebCookieValue('csrf-token')),
    onResponse: (response) => {
      persistKangurMobileCsrfTokenFromHeaders(storage, response.headers);
    },
  });

export const createKangurMobileRuntime = (): KangurMobileRuntime => {
  const apiBaseUrlState = createKangurMobileApiBaseUrlState();
  const storage = createMobileDevelopmentKangurStorage();
  const baseProgressStore = createKangurProgressStore({
    storage,
    progressStorageKey: KANGUR_PROGRESS_STORAGE_KEY,
    ownerStorageKey: KANGUR_PROGRESS_OWNER_STORAGE_KEY,
  });

  return {
    ...apiBaseUrlState,
    apiClient: createKangurMobileApiClient(apiBaseUrlState.apiBaseUrl, storage),
    defaultDailyGoalGames: KANGUR_PROFILE_DEFAULT_DAILY_GOAL_GAMES,
    progressStore: createTrackedKangurMobileProgressStore(baseProgressStore, storage),
    storage,
  };
};

import { kangurScoreSchema, type KangurScore } from '@kangur/contracts/kangur';
import type { KangurClientStorageAdapter } from '@kangur/platform';

const KANGUR_MOBILE_RECENT_RESULTS_STORAGE_KEY = 'kangur.mobile.scores.recent';
const KANGUR_MOBILE_RECENT_RESULTS_SNAPSHOT_LIMIT = 3;

const parsePersistedRecentResultsStore = (
  rawSnapshot: string | null,
): Record<string, KangurScore[]> => {
  const normalizedRawSnapshot = rawSnapshot?.trim() ?? '';
  if (normalizedRawSnapshot === '') {
    return {};
  }

  try {
    const parsedSnapshot = JSON.parse(normalizedRawSnapshot) as unknown;
    if (
      parsedSnapshot === null ||
      parsedSnapshot === undefined ||
      typeof parsedSnapshot !== 'object' ||
      Array.isArray(parsedSnapshot)
    ) {
      return {};
    }

    return Object.entries(parsedSnapshot).reduce<Record<string, KangurScore[]>>(
      (acc, [identityKey, value]) => {
        if (Array.isArray(value)) {
            const parsedResults = kangurScoreSchema
              .array()
              .max(KANGUR_MOBILE_RECENT_RESULTS_SNAPSHOT_LIMIT)
              .safeParse(value);

            if (parsedResults.success) {
              return {
                ...acc,
                [identityKey]: parsedResults.data,
              };
            }
        }
        return acc;
      },
      {},
    );
  } catch {
    return {};
  }
};

export const resolvePersistedKangurMobileRecentResults = ({
  identityKey,
  limit,
  storage,
}: {
  identityKey: string;
  limit: number;
  storage: KangurClientStorageAdapter;
}): KangurScore[] | null => {
  const store = parsePersistedRecentResultsStore(
    storage.getItem(KANGUR_MOBILE_RECENT_RESULTS_STORAGE_KEY),
  );
  const persistedResults = store[identityKey];
  if (persistedResults === undefined) {
    return null;
  }

  return persistedResults.slice(
    0,
    Math.min(limit, KANGUR_MOBILE_RECENT_RESULTS_SNAPSHOT_LIMIT),
  );
};

export const persistKangurMobileRecentResults = ({
  identityKey,
  results,
  storage,
}: {
  identityKey: string;
  results: KangurScore[];
  storage: KangurClientStorageAdapter;
}): void => {
  const store = parsePersistedRecentResultsStore(
    storage.getItem(KANGUR_MOBILE_RECENT_RESULTS_STORAGE_KEY),
  );

  store[identityKey] = results.slice(
    0,
    KANGUR_MOBILE_RECENT_RESULTS_SNAPSHOT_LIMIT,
  );

  storage.setItem(
    KANGUR_MOBILE_RECENT_RESULTS_STORAGE_KEY,
    JSON.stringify(store),
  );
};

import type { KangurScore } from '@kangur/contracts/kangur';

import { useKangurMobileAuth } from '../auth/KangurMobileAuthContext';
import { resolveKangurMobileScoreScope } from '../profile/mobileScoreScope';
import { useKangurMobileRuntime } from '../providers/KangurRuntimeContext';
import { useKangurMobileQueryV2 } from '../query/kangurMobileQueryFactories';

type UseKangurMobileScoreHistoryOptions = {
  enabled?: boolean;
  limit?: number;
  placeholderData?: KangurScore[];
  sort?: string;
};

export type UseKangurMobileScoreHistoryResult = {
  error: Error | null;
  isEnabled: boolean;
  isLoadingAuth: boolean;
  isLoading: boolean;
  isPlaceholderData: boolean;
  isRestoringAuth: boolean;
  refresh: () => Promise<void>;
  scores: KangurScore[];
};

export const useKangurMobileScoreHistory = (
  options: UseKangurMobileScoreHistoryOptions = {},
): UseKangurMobileScoreHistoryResult => {
  const { isLoadingAuth, session } = useKangurMobileAuth();
  const { apiBaseUrl, apiClient } = useKangurMobileRuntime();
  const scoreScope = resolveKangurMobileScoreScope(session.user);

  const limit = getLimit(options.limit);
  const sort = getSort(options.sort);
  const isEnabled = checkIsEnabled(options.enabled, session.status, scoreScope);
  const isRestoringAuth = isLoadingAuth && session.status !== 'authenticated';

  const queryKey = [
    'kangur-mobile',
    'scores',
    apiBaseUrl,
    scoreScope?.identityKey ?? 'anonymous',
    sort,
    limit,
  ] as const;

  const scoresQuery = useKangurMobileQueryV2({
    enabled: isEnabled,
    placeholderData: isEnabled ? options.placeholderData : undefined,
    queryKey,
    queryFn: async () =>
      apiClient.listScores(
        {
          ...scoreScope?.query,
          sort,
          limit,
        },
        {
          cache: 'no-store',
        },
      ),
    staleTime: 30_000,
    meta: {
      source: 'kangur.mobile.scores.history',
      operation: 'list',
      resource: 'kangur.mobile.scores.history',
      queryKey,
      description: 'Loads Kangur mobile score history.',
      tags: ['kangur-mobile', 'scores'],
    },
  });

  return {
    error: scoresQuery.error instanceof Error ? scoresQuery.error : null,
    isEnabled,
    isLoading: isRestoringAuth || scoresQuery.isLoading,
    isLoadingAuth,
    isPlaceholderData: scoresQuery.isPlaceholderData,
    isRestoringAuth,
    refresh: async () => {
      await scoresQuery.refetch();
    },
    scores: scoresQuery.data ?? [],
  };
};

function getLimit(limit?: number): number {
  return typeof limit === 'number' && limit > 0 ? Math.round(limit) : 120;
}

function getSort(sort?: string): string {
  return typeof sort === 'string' && sort.trim().length > 0 ? sort : '-created_date';
}

function checkIsEnabled(enabled: boolean | undefined, status: string, scoreScope: object | null | undefined): boolean {
  return (enabled ?? true) && status === 'authenticated' && Boolean(scoreScope);
}

import {
  createMemoryKangurClientStorage,
  type KangurClientStorageAdapter,
} from '@kangur/platform';

export type KangurNativeFileSystemLike = {
  Paths: {
    document: string;
  };
  Directory: new (...segments: Array<string | { uri?: string }>) => {
    exists: boolean;
    create: () => void;
  };
  File: new (...segments: Array<string | { uri?: string }>) => {
    exists: boolean;
    create: () => void;
    delete: () => void;
    textSync: () => string;
    write: (content: string) => void;
  };
};

let mobileDevelopmentMemoryStorage: KangurClientStorageAdapter | null = null;
let mobileDevelopmentBrowserStorage: KangurClientStorageAdapter | null = null;
let mobileDevelopmentNativeStorage: KangurClientStorageAdapter | null = null;

type KangurMobileDevelopmentStorageMode =
  | 'auto'
  | 'browser'
  | 'memory'
  | 'native';

type CreateMobileDevelopmentKangurStorageOptions = {
  mode?: KangurMobileDevelopmentStorageMode;
  nativeFileSystem?: unknown;
  nativeStorageNamespace?: string;
};

const MOBILE_DEVELOPMENT_NATIVE_STORAGE_NAMESPACE = 'kangur-mobile-dev-native';

const getSharedMemoryStorage = (): KangurClientStorageAdapter => {
  mobileDevelopmentMemoryStorage ??= createMemoryKangurClientStorage();
  return mobileDevelopmentMemoryStorage;
};

const isBrowserStorageAvailable = (): boolean =>
  typeof globalThis !== 'undefined' &&
  'localStorage' in globalThis;

const createBrowserBackedMobileStorage = (): KangurClientStorageAdapter => {
  const listeners = new Set<(change: { key: string | null; value: string | null }) => void>();
  const emitChange = (change: { key: string | null; value: string | null }): void => {
    listeners.forEach((listener) => listener(change));
  };

  return {
    getItem: (key) => globalThis.localStorage.getItem(key),
    removeItem: (key) => {
      globalThis.localStorage.removeItem(key);
      emitChange({ key, value: null });
    },
    setItem: (key, value) => {
      globalThis.localStorage.setItem(key, value);
      emitChange({ key, value });
    },
    subscribe: (listener) => {
      listeners.add(listener);
      return () => {
        listeners.delete(listener);
      };
    },
  };
};

const serializeSnapshot = (snapshot: Record<string, string>): string =>
  JSON.stringify(snapshot);

const deserializeSnapshot = (payload: string | null): Record<string, string> => {
  if (typeof payload !== 'string' || payload.trim().length === 0) {
    return {};
  }

  try {
    const parsed = JSON.parse(payload);
    if (
      typeof parsed !== 'object' ||
      parsed === null ||
      Array.isArray(parsed)
    ) {
      return {};
    }

    return Object.fromEntries(
      Object.entries(parsed).filter(
        ([, value]) => typeof value === 'string',
      ),
    ) as Record<string, string>;
  } catch {
    return {};
  }
};

const createNativeFileBackedMobileStorage = (
  nativeFileSystem: KangurNativeFileSystemLike,
  namespace: string,
): KangurClientStorageAdapter => {
  const listeners = new Set<(change: { key: string | null; value: string | null }) => void>();
  const emitChange = (change: { key: string | null; value: string | null }): void => {
    listeners.forEach((listener) => listener(change));
  };
  const documentDirectory = new nativeFileSystem.Directory(nativeFileSystem.Paths.document);
  const storageFile = new nativeFileSystem.File(
    nativeFileSystem.Paths.document,
    namespace,
  );
  let snapshot: Record<string, string> | null = null;

  const loadSnapshot = (): Record<string, string> => {
    if (snapshot !== null) {
      return snapshot;
    }

    if (!documentDirectory.exists) {
      documentDirectory.create();
    }

    if (!storageFile.exists) {
      storageFile.create();
      snapshot = {};
      return snapshot;
    }

    const raw = storageFile.textSync();
    snapshot = deserializeSnapshot(raw);
    return snapshot;
  };

  const persistSnapshot = (): void => {
    if (!documentDirectory.exists) {
      documentDirectory.create();
    }
    if (!storageFile.exists) {
      storageFile.create();
    }
    storageFile.write(serializeSnapshot(snapshot ?? {}));
  };

  const resolveItem = (key: string): string | null => {
    const currentSnapshot = loadSnapshot();
    if (!(key in currentSnapshot)) {
      return null;
    }
    return currentSnapshot[key] ?? null;
  };

  const removeItem = (key: string): void => {
    const currentSnapshot = loadSnapshot();
    delete currentSnapshot[key];
    persistSnapshot();
    emitChange({ key, value: null });
  };

  const setItem = (key: string, value: string): void => {
    const currentSnapshot = loadSnapshot();
    currentSnapshot[key] = value;
    persistSnapshot();
    emitChange({ key, value });
  };

  return {
    getItem: resolveItem,
    removeItem,
    setItem,
    subscribe: (listener) => {
      listeners.add(listener);
      return () => {
        listeners.delete(listener);
      };
    },
  };
};

const loadExpoFileSystem = (): KangurNativeFileSystemLike | null => {
  try {

    const expoFileSystem = require('expo-file-system');
    const normalizedModule =
      expoFileSystem?.default ?? expoFileSystem?.FileSystem ?? expoFileSystem;
    if (
      normalizedModule &&
      typeof normalizedModule.Paths === 'object' &&
      typeof normalizedModule.Paths.document === 'string' &&
      typeof normalizedModule.Directory === 'function' &&
      typeof normalizedModule.File === 'function'
    ) {
      return normalizedModule as KangurNativeFileSystemLike;
    }
  } catch {
    // no-op
  }

  return null;
};

const createStorage = (
  mode: KangurMobileDevelopmentStorageMode,
  options: CreateMobileDevelopmentKangurStorageOptions,
): KangurClientStorageAdapter => {
  if (mode === 'memory') {
    return getSharedMemoryStorage();
  }

  if (mode === 'browser') {
    if (!isBrowserStorageAvailable()) {
      return getSharedMemoryStorage();
    }
    mobileDevelopmentBrowserStorage ??= createBrowserBackedMobileStorage();
    return mobileDevelopmentBrowserStorage;
  }

  if (mode === 'native') {
    const nativeFileSystem =
      (options.nativeFileSystem as KangurNativeFileSystemLike | undefined) ??
      loadExpoFileSystem();
    if (nativeFileSystem) {
      mobileDevelopmentNativeStorage ??=
        createNativeFileBackedMobileStorage(
          nativeFileSystem,
          options.nativeStorageNamespace ??
            MOBILE_DEVELOPMENT_NATIVE_STORAGE_NAMESPACE,
        );
      return mobileDevelopmentNativeStorage;
    }

    return getSharedMemoryStorage();
  }

  const nativeFileSystem =
    (options.nativeFileSystem as KangurNativeFileSystemLike | undefined) ??
    loadExpoFileSystem();
  if (isBrowserStorageAvailable()) {
    mobileDevelopmentBrowserStorage ??= createBrowserBackedMobileStorage();
    return mobileDevelopmentBrowserStorage;
  }
  if (nativeFileSystem) {
    mobileDevelopmentNativeStorage ??=
      createNativeFileBackedMobileStorage(
        nativeFileSystem,
        options.nativeStorageNamespace ??
          MOBILE_DEVELOPMENT_NATIVE_STORAGE_NAMESPACE,
      );
    return mobileDevelopmentNativeStorage;
  }

  return getSharedMemoryStorage();
};

const createStorageForMode = (
  mode: string,
  options: CreateMobileDevelopmentKangurStorageOptions,
): KangurClientStorageAdapter =>
  createStorage(mode as KangurMobileDevelopmentStorageMode, options);

export const resetMobileDevelopmentKangurStorage = (): void => {
  mobileDevelopmentMemoryStorage = null;
  mobileDevelopmentBrowserStorage = null;
  mobileDevelopmentNativeStorage = null;
};

export const createMobileDevelopmentKangurStorage = (
  options: CreateMobileDevelopmentKangurStorageOptions = {},
): KangurClientStorageAdapter => {
  return createStorageForMode(options.mode ?? 'auto', options);
};
